INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("やばいですね☆なの！", 1, 3, "プリンセスなプリンなの\nお店にあったいろんな食べもの\nを入れられるだけ入れてみたの\nどんな味なのか楽しみなの", "おいしすぎて食べ始めたら\n止まらない最高のプリンなの\n今のミヤコを止められるヤツは\n誰もいないの", 5, 1, "ペコリーヌのプリン", 100);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("主さま、なの！", 1, 3, "いつもオマエのそばに寄りそう\nヤツのぷりんなの。ミヤコの\nワガママもやさしく受け入れて\nくれそうなの", "なんだかすごくやさしい気持ち\nになる味なの…\nおはようからおやすみまで\nずっと一緒な味なの…", 5, 2, "コッコロのプリン", 101);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("ぶっ殺すぞ！なの！\n…デレデレはどこなの？", 0, 3, "ツンツンデレデレなヤツの\nプリンなの。砂糖とスパイスを\n混ぜてみたの。どんな味になる\nか楽しみなの", "いろんな味が一度で楽しめる\nプリンなの。ツンデレはプリン\nにするとおいしいの。ミヤコも\nツンデレを目指してみるの", 5, 3, "キャルのプリン", 102);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("おにーたん♪なの！", 1, 3, "オマエと同じで、一度赤ちゃん\nみたいになったヤツのプリン\nなの。ヒンヤリ、プリンアイス\nにしてみたの", "あったかいところで食べる\nプリンアイスは最高なの～♪\n安心しすぎて昔の記憶のない\nミヤコも心が子どもになるの～", 5, 4, "シェフィのプリン", 103);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("ハーハッハッハ！\n世界征服なのじゃなのー！", 1, 3, "イリヤを見てたら思いついた\nトマトジュースが隠し味の\nプリンなの。栄養満点なの", "トマトで栄養補給も完璧なの\nどんどん力がみなぎってきて\n復活も夢じゃないの\nミヤコが復活したら…", 5, 5, "イリヤのプリン", 104);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("お兄ちゃんのエッチ！　なの！", 1, 3, "アカリのプリンなの。ヨリと\n同じくらいかわいく作って\nやったの。正直ミヤコは\nおいしければなんでもいいの", "見た目がかわいくてもミヤコは\n味にも厳しいの。あむっ…\nこ、これは…！なんだかすごく\n変な気分になってきたの…", 5, 6, "アカリのプリン", 105);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("えっと…その…あんたのこと…\nだ、大っ嫌いなのーー！", 1, 3, "かわいくつくらないとアカリが\n怒りそうだからヨリのプリンは\nかわいく作ったの。自信作なの", "んむぅ…これはなかなか感想が\n難しいプリンなの…率直に言い\nたいような…心のうちに秘めて\nおきたいような…", 5, 7, "ヨリのプリン", 106);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("お父さん…\nいいかげんにしてなの！\nん？プリンの未来は…\n見えなかったの…", 0, 3, "シノブはいつもミヤコに\nやさしくしてくれるから\n丁寧に作ったの。ドクロ親父は\nいらないから作ってないの", "このプリンを食べるとシノブが\nミヤコの中にいるみたいなの！\nシノブの力があれば未来の\nプリンを見放題なの！", 5, 8, "シノブのプリン", 107);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("インフェルノシールド！なの！", 1, 3, "黒い鎧を脱がないヤツのプリン\nなの。固めのプリンを目指したら\nカチカチになりすぎたの", "固すぎてかじれないから丸吞み\nにしたの。なんだか体が硬く\nなった気がするの。みんなを\n守れる気がするの！", 5, 9, "ジュンのプリン", 108);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("あなたといると調子が狂うな\n…なの\n翻弄してたのはオマエなの？", 1, 3, "オマエをいっつもからかってる\nヤツのプリンなの\nちょっぴり変わったスパイスで\nからかいを表現したの", "口の中でスパイスがプチプチ\nはじけて新食感なの！\nプチプチがミヤコを\n翻弄するの！", 5, 10, "トモのプリン", 109);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("タイガーヒーローボンバー！\nなの！", 1, 3, "王宮騎士団にいるちっこいヤツ\nなの。ちっこいけどやるヤツ\nらしいから、濃いめの味付けに\nしてみたの", "ん～見かけによらず濃厚な\nパンチのある味わいが\n口いっぱいに広がるの！", 5, 11, "マツリのプリン", 110);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("ま、いいんじゃん？\nしらんけどなの", 1, 3, "なんかすごくクールなプリンなの\nなんかテンションも少し\n低そうなの。これ\n食べちゃっても大丈夫なの？", "クールな見た目なのにとっても\n優しい味なの！なんだか\n懐かしさを感じるの…", 5, 13, "クロエのプリン", 111);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("ぷりーん★なの！", 1, 3, "きれいにデコれたの！\nカラフルでおいしそうなの\nこれは期待できそうなの", "なんか変わった食感なの…\nちゃる…ちょる…ちぇる？\nちぇるってしてるの\nでもちぇるってなんなの？", 5, 14, "チエルのプリン", 112);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("端的に換言すれば\n青春の味なの？", 1, 3, "見た目は完ぺきなの！\nこれをつくったやつは\nきっと天才なの！\n早く食べたいの！", "味はなんか妙に\n甘酸っぱいの…\n食べたことない味なの\nこの味ってもしかして…", 5, 15, "ユニのプリン", 113);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("幼なじみはあんた…なの？", 1, 3, "オマエから聞いた懐かしい\n味ってヤツを全部入れてみたの\nオマエ記憶がないのに懐かしい\nってどういうことなの？", "ミヤコも幽霊になる前の記憶\nがないのに、なんだか懐かしい\n気持ちになってくるの…", 5, 16, "サレンのプリン", 114);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("ひゃああんなの～！", 1, 3, "たまたま会ったメイドに教えて\nもらった作り方なの。メイドは\nプリンも作れるはずなの。\nなのにこの不安は何なの…？", "おかしいの。このプリンを\n食べてから、３回も転んだの\nミヤコは幽霊だから転んだり\nしないの。なんでなの…？", 5, 17, "スズメのプリン", 115);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("サルキデバレヤ！なの！", 0, 3, "怖がりな子どもが教えてくれた\n小さくてかわいいプリンなの　\n触ってないのにぷるぷる震える\n驚きのやわらかさなの", "甘さのなかに少しのしょっぱさ\nクセになる味なの\nこのプリンはがんばればきっと\nいろんな美味しいになれるの", 5, 18, "クルミのプリン", 116);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("プリンフルスイングなの～！", 1, 3, "くまのぬいぐるみを見ていたら\nひらめいたの。小さいけど\nしっかりした甘さの元気に\nなれるプリンなの！", "このプリン、食べるとなんだか\nお姉ちゃんになった気分に\nなるの。ピンチのプリンは\nミヤコが守ってやるの！", 5, 19, "アヤネのプリン", 117);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("みらくるみやりん\nくるりんぱ～☆なの！", 1, 3, "マホマホ王国って国にいる\nお姫様のプリンなの\n魔物も虜にしちゃう\nすてきなプリンなの", "メルヘンパワーがあふれてきて\nいまならミヤコにも魔法が\n使える気がするの！\nほな、いきまひょ～なの！", 5, 20, "マホのプリン", 118);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("ウルフェンバイトなの！", 1, 3, "カッコいいプリンを目指して\nワイルドなものをガンガン\n入れてみたの。きっと熱い\nプリンができるはずなの", "うおーん！ミヤコなんだか\n強くなった気がするの！\n困ったことがあればミヤコが\nまとめて面倒見てやるの！", 5, 21, "マコトのプリン", 119);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("なんくるないさ～！なの！", 1, 3, "どっかの国でよくとれる\nゴーヤーに似てるやつを\nいれてみたの！ちょっと\n苦いらしいけど…", "一口食べたら元気が\nあふれて止まらないの！\n気分がいいから、一曲\n踊りでも披露してやるの！", 5, 22, "カオリのプリン", 120);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("ふふん。簡単な推理なの", 1, 3, "勘の鋭いやつが好きな食べ物を\nたくさん入れてみたの\n難しいこと考えるのにぴったり\nらしいけど、なんでなの？", "むむむ…なるほどなの\n上質な糖分をふんだんに\n使うことで、脳をより活性化\nできるからなの！", 5, 23, "カスミのプリン", 121);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("エリザベス～！なの～！", 1, 3, "搾りたての牛乳を\nたっぷり使ったプリンなの～\nマヒルに手伝ってもらって\nミヤコ直々に搾ってきたの！", "ミルクがとっても濃厚で\nほっぺたが落ちちゃうの～♪\nこのプリンからは牧場の…\n自然の息吹を感じるの！", 5, 24, "マヒルのプリン", 122);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("私の好きな本…読んで\nもらえたらうれしいです…\nなの", 1, 3, "マヒルからやさしいヤツだって\n聞いたの。やさしさを表現\nするために奥ゆかしい甘さに\n仕上げてみたの", "ほのかな甘さでありながら\nしっかりとした主張も\n感じさせる\n味わい深いプリンなの", 5, 25, "シオリのプリン", 123);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("もふもふにしてあげるなの！", 1, 3, "牧場にいるヤツらしいの\n牛とは違うらしいの\nもふもふ気持ちいいらしいから\n食感にこだわって作ったの", "こ、これは…！口の中に入れた\n瞬間にふんわり溶けて\nなくなっちゃうの！\nその食感がやみつきなの！", 5, 26, "リマのプリン", 124);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("めんどくさいな～なの…", 0, 3, "いっつも寝てるやつらしいの\nぐっすり眠れる薬草をたくさん\n入れてみたの。プリンとして\nおいしくなるかはわからないの", "んむぅ…評価が難しい味なの…\nおいしいのはおいしいの…\nん～考えてたら…\n眠くなってきたの…", 5, 27, "リンのプリン", 125);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("プリンの権能を解放するの～！", 1, 3, "クレープ屋の真っ赤な人に\n教わったプリンなの\n作り方を丁寧に教えてくれて\nとっても優しい人だったの！", "プ…プリンなのにクレープの味\nがするの。味もすごく普通なの\nでも…なんだかプリンの新しい\n扉を開けそうな気がするの…！", 5, 28, "ラビリスタのプリン", 126);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("お姉ちゃんパワー全開！なの！", 0, 3, "お店に落ちてた謎のレシピの\nプリンなの。レシピの表紙には\n『お姉ちゃんの愛情たっぷり』\nって書いてあったの", "とろける食感が絶品なの～♪\n食べるとなんだか幸せな\n気持ちになれるの…これが\n愛情ってやつなの？", 5, 29, "シズルのプリン", 127);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("お兄ちゃん、プリンをよこすの！", 1, 3, "リノから作り方を教わったの！\nさすがクレープ屋で働いてる\nだけあって美味しそうなの！", "これで妹力？があがるらしいの。\n妹になればお兄ちゃんに\nプリンをたかり放題なの！\n最高なの～！", 5, 30, "リノのプリン", 128);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("困った時はお互いさまさま！\nなの！", 1, 3, "プリンのレシピで悩んでたら\n通りすがりのおねーさんが\n一緒に考えてくれたプリンなの\nいいヤツもたまにはいるの～♪", "食べたら元気が湧いてくるの\nだからプリンのレシピのお礼に\nミヤコも人助けを手伝って\nやったの。ミヤコはえらいの！", 5, 31, "ヒヨリのプリン", 129);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("フラワリングヒールなの～♪", 1, 3, "ミヤコががんばって作った\nこだわりのプリンなの～\nプリンは癒しなの。だから優しい\n気持ちで丁寧に作ったの", "はっ…思わずお花畑が見えたの\n身も心も包まれるような\nとっても優しい味がするの\nこれは…まさに癒しなの～♪", 5, 32, "ユイのプリン", 130);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("スラッシュテンペスト！なの。", 1, 3, "究極のプリンを作るため\nミヤコは厳しい修行をしたの…\nその結果あって完成した\nクールで完璧なプリンなの！", "確かに完璧なプリンなの\nでも究極のプリンと呼ぶには\nまだまだ修行が必要なの…\nプリン作りは奥が深いの…！", 5, 33, "レイのプリン", 131);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("おーほっほほほ！なの！", 1, 3, "豪華で高級な\nお嬢様プリンなの\n中には宝石みたいな\n大きいイチゴを入れるの！", "味にも素材にもこだわりが\nあるの。一流は妥協しないの\nもっと豪華に、もっとおいしく\nできるはず…", 5, 34, "アキノのプリン", 132);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("プリしゅわ最高～！なの！", 1, 3, "外はしっかり、中はふわとろの\nプリンにするの\n泡みたいなしゅわしゅわの\n生クリームも入れるの♪", "プリンは飲み物とも言うの\nぐいっていってみるの\n…ふわしゅわでとろけるの～！\n体に染みわたるの～", 5, 35, "ユカリのプリン", 133);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("にゃにゃにゃ！なの！", 1, 3, "餡子を入れて\nオーブンでこんがり焼くの\nたい…焼きプリンなの\n斬新なの！", "このプリンは焼きたてのうちに\n食べるのが一番なの…！\n熱いけどおいしくて\nうずうずしてきたの…！", 5, 36, "タマキのプリン", 134);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("効率全開！なの！", 0, 3, "栄養バランスを考えて\n木の実をたくさん入れるの\nあれこれ忙しいときでも\n頼りになるプリンなの！", "プリンはいつでも手軽に\n食べられるのも魅力なの\nこれは食べ応えもあるから一つ\n食べればいっぱい動けるの", 5, 37, "ミフユのプリン", 135);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("あらあら～なの～♪", 1, 3, "エルフの森で子どもにもらった\n薬草を使って作ったの\nこんな優しい味のプリンは\n初めてなの…", "このプリンを食べてから\nいい子になった気がするの\n大好きなプリンを泣いてる子に\nあげたの。いい気分なの", 5, 38, "ミサトのプリン", 136);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("スヤスヤ～…なの…", 1, 3, "お昼寝でみた夢の中に\nでてきた不思議なプリンを\n作ってみたの。見てたらまた\n眠くなってきたの…", "あまいプリンが口の中で\nぽんぽん弾ける未知の味なの！\n今なら不思議な力で世界も\n救えそうなの！でも眠くなるの…", 5, 39, "ハツネのプリン", 137);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("ぼっちは卒業なの～！", 1, 3, "お店のはしっこに一つだけ\n残ったおもちゃを見て思い\nついたの。他のプリンと一緒に\n置いておくと震えだすの", "知らないうちにはしっこに\n隠れちゃってたの。食べたら\nミヤコ、シノブたちに会いに\nいきたくなってきたの", 5, 40, "アオイのプリン", 138);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("リズムあげるのー！", 1, 3, "トップオブアイドルの\nプリンなの。キラキラした\nものを入れて、あつ～い\nオーブンで焼いてみたの", "口の中に華やかな甘さが\n広がる…これがアイドルなの？\n急に歌って踊りたく\nなってきたの！", 5, 41, "ノゾミのプリン", 139);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("風の加護を！なの！", 1, 3, "ミヤコにプリンをくれるすごく\nいいヤツのプリンなの\n精霊に呼びかけながら\n一生懸命かき混ぜたの", "プリンの生地がとっても\nなめらかで最高の舌触りなの！\n精霊、ミヤコのプリンのために…", 5, 42, "チカのプリン", 140);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("騎士さんのために\nしたんじゃありません！なの！", 1, 3, "歌って踊って衣装も作れるヤツ\nのプリンなの。このプリンは\nきれいに包装するの。プリンを\n最高の形で着飾らせるの", "包装は食べるまでの手間が\n増えてめんどくさいの。でも\nそのめんどくささもプリンの\n味を引き立てるの", 5, 43, "ツムギのプリン", 141);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("宴の始まりなの！", 0, 3, "プリンをくれないならどうでも\nいいヤツなの。でも横で\nいろいろ言ってきたから\nがんばって作ったの", "んむっ！？\nく、口のなかでプリンの\nおいしさが大暴れなの！\n止まらないの！", 5, 12, "クリスティーナのプリン", 142);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("一刀両断、覚悟しな！なの！", 1, 3, "大人な甘さ控えめのプリンを\n作るの。試しにお魚を入れて\nみるの。プリンの可能性は\n無限大なの！", "大人の味なの。今やミヤコは\nみんなの頼れる姐御なの！\n悪さするやつはミヤコが\n許さないの！", 5, 44, "ルカのプリン", 143);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("きゅぴーん！キタコレ！なの！", 1, 3, "サイカワサイツヨな\n魔法のプリンなの\n中身をカラフルにするの～\n甘いプリンは頭が冴えるの！", "一口食べる度に味が変わって\n魔法みたいなの！\nもしかして全部食べたら\nミヤコも魔法少女になれるの？", 5, 45, "ナナカのプリン", 144);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("人呼んで、疾風のミヤコなの！", 1, 3, "小難しい言葉をささやきながら\n作ったら魔力あふれるプリンが\n爆誕したの！でも、不思議と\nイタイタしいのはなぜなの～？", "一口食べたら謎の組織に\n狙われたり、前世の記憶が蘇る\n気がするの～設定盛りすぎなの\nミヤコは、ミヤコは…", 5, 46, "アンナのプリン", 145);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("クスクス…クスクスクス…なの", 1, 3, "甘酸っぱい赤い木の実を\n切り刻んで入れるの\n甘くてちょっぴり刺激的な\nヤンデレのプリンなの", "なんか普通のプリンよりも\nいい匂いがするの～…\nプリンのことがもっともっと\n好きになっちゃうの…", 5, 47, "エリコのプリン", 146);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("どんなプリンも\nミヤコの隻眼からは\n逃れられないの～！", 1, 3, "健康に気を遣うミヤコは\nプリンにお薬を入れてみたの～\nでもなんだか毒々しいから\n彩りにバラを添えてみたの～", "鼻に抜ける薬のにおいがアレ\nだけど大人っぽくて頭が\nよくなった気がするの。無性に\n実験したくてしかたないの", 5, 48, "ミツキのプリン", 147);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("私は子どもではない！なの！", 1, 3, "小さいけどしっかりした\n軍人のプリンなの\nちょっと固めにして\n砂糖はいっぱい入れるの", "ん～王道なプリンは\n甘くて安定したおいしさなの～\n思わず笑顔になっちゃうの\nにこにこなの～♪…はっ！", 5, 49, "モニカのプリン", 148);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("ショーグン！　ミヤコと一緒に\n天下統一するデースなの！", 1, 3, "オーエド町で手に入れた素材と\nトーゴクに伝わる術をかけて\nプリンを作るの。シュババ！\n忍法隠し味の術なの！", "このプリンを食べてから\n誰かにお仕えしなきゃ\nいけない気がするデースなの\nそれはショ、ショー…", 5, 50, "ニノンのプリン", 149);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("…ぐふふ、じゅるり～なの", 0, 3, "オマエが持ってきた手錠を\nヒントに作ったプリンなの\nプリンが動けないように\nカチカチに固めたの", "カチカチに固めたせいで食感が\nプリンのようで\nプリンじゃないの…でもこの\nもどかしさが癖になるの…", 5, 51, "クウカのプリン", 150);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("あぁ、ミヤコはなんて美しいの～", 1, 3, "とっても美しいプリンなの\n美しいものを手当たり次第\n入れたらすごいことになったの", "味も美しい以外の感想が\n出てこないの。ていうかこれを\n食べたミヤコも美しいの！\n鏡、鏡はどこなの！", 5, 52, "ユキのプリン", 151);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("ジー…ってミヤコなにしてるの\nミヤコはストーカーじゃないの！", 0, 3, "知らないうちにお菓子が売れた\n時に思いついたプリンなの。\n作り方もよく覚えてない…\nけど、きっとおいしいの！", "うん、やっぱりおいしく…\nん？あそこにいるのは\nアイツなの。あれ？\n体が勝手にアイツの方に…", 5, 53, "アユミのプリン", 152);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("にひひ…イタズラの時間なの！", 0, 3, "イタズラ好きの手下と一緒に\n作ったプリンなの。見た目は\nかわいいけど、作り方は\n意外と複雑なの～", "見た目通り甘々で優しい味なの\nでも、レシピを見たら裏面に\n別の作り方が書いてあるの。\nこれだと激辛プリンに…", 5, 54, "ミソギのプリン", 153);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("ぴょんぴょこぴょーん、なの♪", 0, 3, "素直でやさしい手下と一緒に\n動物のぬいぐるみをいっぱい\n並べて作ったの", "ん～、ふわふわの甘々なの！\nなんだか楽しくなって\n心も体もるんたったしてくるの", 5, 55, "ミミのプリン", 154);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("へんたいふしんしゃさんなの！", 0, 3, "幽霊を怖がっている手下と\n一緒に作ったプリンなの。\n小さいクセにきっちりしてて\nとってもかわいいプリンなの", "ひんやりしてて暑い日でも\nおいしく食べられそうなの！\nん？これを買いたい大人が\nいる？それって…", 5, 56, "キョウカのプリン", 155);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("ハート狙い撃ち！なの！", 1, 3, "カリスマモデルなプリンなの\nモリモリにデコレーションして\nカリスマ感を演出したの", "見て食べて楽しめる新機軸の\nプリンなの。ミヤコは幽霊\nだけど自分の足でランウェイを\n歩きたくなってきたの！", 5, 57, "スズナのプリン", 156);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("授業を始めます♪なの！", 0, 3, "学校の先生をしてるヤツの\nプリンなの。お堅くしようと\nしたら、いつの間にか色っぽく\nなっちゃったの。なんでなの？", "プ、プリンは全部ミヤコのもの\nなのに、なんだかこのプリンは\nいろんな人に教えたく\nなっちゃう不思議な味なの！", 5, 58, "イオのプリン", 157);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("立派なレディ、なの！", 1, 3, "少し背伸びしたおませな子を\n表現したプリンなの。あえて\n甘さ控えめなの。カラメルは\n後乗せできるから安心するの", "ミヤコはプリンならどんなもの\nでも食べるの。でもカラメルを\nちょっとだけ足すの。\nちょっとだけなら…", 5, 59, "ミサキのプリン", 158);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("プリンを持ってこないと\nお仕置きだよ～☆なの！", 1, 3, "謎に包まれたプリンができたの\n何か隠してるようなの…\nこれは危険なプリンなの！", "味はすごいゴージャスなの！\nボスの風格があるの！\nビッグなミヤコに\nプリンを捧げるの！", 5, 60, "ホマレのプリン", 159);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("たぎってきたの！", 1, 3, "ワイルドな見た目なの！\nこれは期待できそうなの。\nきっと躍動感あふれる味なの！", "最初の一口目が\nすごいインパクトなの！\n無性にケンカしたくなるの！\nプリンをよこせなの！", 5, 61, "カヤのプリン", 160);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("下剋上、やってやるですなの！", 0, 3, "なんか見た目がパッとしないの\nこれほんとに大丈夫なの？\nなんか頼りないの…", "見た目はアレだけど味はおいし\nいの…あと主張もはっきりして\nるの！やる気と自信だけは\n出てきたのうおおおーなの！", 5, 62, "イノリのプリン", 161);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("どけどけ～！なの～！", 1, 3, "天下の大悪党のプリンなの\nこれまでのジョーシキに\n捉われないプリンを\n作ってみたの～", "むむむ…食べたら\nやる気が湧いてきたの！\nミヤコを邪魔するやつはみんな\nまとめてぶっ飛ばしてやるの～", 5, 63, "ムイミのプリン", 162);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("ミラーミラー！なの！", 1, 3, "いろんなものに変身したり\n分身したりできるヤツの\nプリンなの。型で同じプリンを\nたくさんたくさん作ったの", "いつのまにか作ったの全部\n食べちゃったの。なんで\nプリンは分身しないの？\n無限に増えろなの！", 5, 64, "ネネカのプリン", 163);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("プリンに忠誠を誓いますわ！\nなの！", 1, 3, "金の亡者のプリンなの\n金にものを言わせて作って\nみたの。おばあちゃんの\nプリンと対極なの", "むぅ…認めたくないけど\nおいしいの…これを何個も\n作れるほどのお金を稼ぐのは\n大変なの…でもおいしいから…", 5, 65, "クレジッタのプリン", 164);
INSERT INTO `v1_d6bdedd4ba35da4f98cf2b2fa9cf3fdfc1954e7d3f6f3e3f23cb3b3c4f1b3961` VALUES ("ギルド管理協会へようこそ！\nなの！", 1, 3, "みんなお世話になるギルド\n管理協会職員のプリンなの\nお役所感を出すために手堅く\n王道に作ったの", "手堅い…！手堅いの…！\n隙のないプリンなの！\n今のミヤコなら完璧な\n書類作成ができそうなの！", 5, 66, "カリンのプリン", 165);
